commands_run:
cat <<'EOF' > verify_active_task_clip_integration.mjs
import { readFileSync } from 'node:fs';
import { strict as assert } from 'node:assert';

const repoRoot = '/Users/peteromalley/Documents/reigh-workspace/reigh-app';

function read(relativePath) {
  return readFileSync(`${repoRoot}/${relativePath}`, 'utf8');
}

const pendingGenerationTasks = read('src/shared/hooks/tasks/usePendingGenerationTasks.ts');
const activeTaskClips = read('src/tools/video-editor/hooks/useActiveTaskClips.ts');
const timelineEditor = read('src/tools/video-editor/components/TimelineEditor/TimelineEditor.tsx');
const clipAction = read('src/tools/video-editor/components/TimelineEditor/ClipAction.tsx');

assert.match(
  pendingGenerationTasks,
  /const \{ getSupabaseClient \} = await import\('@\/integrations\/supabase\/client'\);/,
  'usePendingGenerationTasks should avoid the restricted static Supabase facade import.'
);

assert.match(
  activeTaskClips,
  /useSyncExternalStore[\s\S]*return realtimeEventProcessor\.onEvent\(\(event\) => \{/,
  'useActiveTaskClips should keep optimistic state plus a realtime subscription that returns cleanup on unmount.'
);
assert.match(
  activeTaskClips,
  /const activeTaskAssetKeys = useMemo\(\(\) => \{[\s\S]*optimisticActiveAssetKeys[\s\S]*queriedActiveAssetKeys[\s\S]*\}, \[optimisticActiveAssetKeys, queriedActiveAssetKeys\]\);/,
  'useActiveTaskClips should union queried and optimistic active asset keys.'
);

assert.match(
  timelineEditor,
  /const \{ activeTaskAssetKeys \} = useActiveTaskClips\(\{ registry: resolvedConfig\?\.registry \}\);/,
  'TimelineEditor should subscribe to active task clip state from the resolved registry.'
);
assert.match(
  timelineEditor,
  /const isTaskActive = assetKey \? activeTaskAssetKeys\.has\(assetKey\) : false;[\s\S]*<ClipAction[\s\S]*isTaskActive=\{isTaskActive\}/,
  'TimelineEditor should derive isTaskActive per clip and pass it to ClipAction.'
);

assert.match(
  clipAction,
  /isTaskActive \? \([\s\S]*Loader2 className="h-2\.5 w-2\.5 animate-spin"[\s\S]*\) : isVariantStale \? \(/,
  'ClipAction should render the spinner with priority over the stale badge.'
);
assert.match(
  clipAction,
  /if \(prev\.isTaskActive !== next\.isTaskActive\) return false;/,
  'ClipAction memo equality should include isTaskActive.'
);

console.log('Active task clip integration verified.');
EOF
node verify_active_task_clip_integration.mjs
rm verify_active_task_clip_integration.mjs
